window.COMPARE_FIGHT_LEDGER = {"jose aldo|max holloway": {"fighters": ["Jose Aldo", "Max Holloway"], "fights": 2, "winner": "Max Holloway", "importance": "major", "summary": "Holloway stopped Aldo twice in UFC featherweight title fights, giving Max two massive direct wins over a divisional legend."}, "alexander volkanovski|max holloway": {"fighters": ["Alexander Volkanovski", "Max Holloway"], "fights": 3, "winner": "Alexander Volkanovski", "importance": "major", "summary": "Volkanovski beat Holloway three times, creating clear direct separation in the featherweight GOAT debate even though Max still owns huge longevity and quality-win value."}, "alexander volkanovski|jose aldo": {"fighters": ["Alexander Volkanovski", "Jose Aldo"], "fights": 1, "winner": "Alexander Volkanovski", "importance": "major", "summary": "Volkanovski beat Aldo before winning the belt, giving Volk a clean bridge win between featherweight eras."}, "conor mcgregor|max holloway": {"fighters": ["Conor McGregor", "Max Holloway"], "fights": 1, "winner": "Conor McGregor", "importance": "contextual", "summary": "McGregor beat Holloway early in both men's UFC runs. It matters as a direct result, but it should not override Holloway's much longer later featherweight resume."}, "conor mcgregor|jose aldo": {"fighters": ["Conor McGregor", "Jose Aldo"], "fights": 1, "winner": "Conor McGregor", "importance": "major", "summary": "McGregor knocked out Aldo to win the featherweight title, one of the biggest single legacy wins in UFC history and the center of Conor's peak case."}, "conor mcgregor|khabib nurmagomedov": {"fighters": ["Conor McGregor", "Khabib Nurmagomedov"], "fights": 1, "winner": "Khabib Nurmagomedov", "importance": "major", "summary": "Khabib submitted McGregor in their lightweight title fight, giving Khabib the direct rivalry edge in one of the biggest fights in UFC history."}, "demetrious johnson|henry cejudo": {"fighters": ["Demetrious Johnson", "Henry Cejudo"], "fights": 2, "winner": "Split", "importance": "major", "summary": "Johnson finished Cejudo first, then Cejudo won the close rematch to take the flyweight title. The split is central to both men's UFC cases."}, "dominick cruz|demetrious johnson": {"fighters": ["Dominick Cruz", "Demetrious Johnson"], "fights": 1, "winner": "Dominick Cruz", "importance": "contextual", "summary": "Cruz beat DJ at bantamweight before DJ became the flyweight standard. It matters historically, but it should be treated with division and career-stage context."}, "dominick cruz|henry cejudo": {"fighters": ["Dominick Cruz", "Henry Cejudo"], "fights": 1, "winner": "Henry Cejudo", "importance": "major", "summary": "Cejudo stopped Cruz in a bantamweight title fight, giving Henry a direct win over an all-time bantamweight name, even with comeback/context questions around Cruz."}, "georges st-pierre|matt hughes": {"fighters": ["Georges St-Pierre", "Matt Hughes"], "fights": 3, "winner": "Georges St-Pierre", "importance": "major", "summary": "Hughes beat young GSP first, but GSP won the next two and took clear generational separation at welterweight."}, "georges st-pierre|bj penn": {"fighters": ["Georges St-Pierre", "BJ Penn"], "fights": 2, "winner": "Georges St-Pierre", "importance": "major", "summary": "GSP beat Penn twice, including a dominant championship rematch, which adds major value to GSP's opponent-quality case."}, "georges st-pierre|matt serra": {"fighters": ["Georges St-Pierre", "Matt Serra"], "fights": 2, "winner": "Split", "importance": "major", "summary": "Serra's upset is the biggest blemish on GSP's record, but GSP avenged it emphatically to restore the championship arc."}, "anderson silva|chael sonnen": {"fighters": ["Anderson Silva", "Chael Sonnen"], "fights": 2, "winner": "Anderson Silva", "importance": "major", "summary": "Anderson beat Sonnen twice, including the famous late comeback in their first fight, which became one of the defining moments of his reign."}, "jon jones|daniel cormier": {"fighters": ["Jon Jones", "Daniel Cormier"], "fights": 2, "winner": "Jon Jones", "importance": "major", "summary": "Jones beat Cormier officially in their first fight, while the rematch was overturned to a no contest. Even with the messy context, Jones holds the direct rivalry separation."}, "jon jones|alexander gustafsson": {"fighters": ["Jon Jones", "Alexander Gustafsson"], "fights": 2, "winner": "Jon Jones", "importance": "major", "summary": "Jones beat Gustafsson twice: the first was a classic close title fight, and the rematch gave Jones much cleaner separation."}, "islam makhachev|alexander volkanovski": {"fighters": ["Islam Makhachev", "Alexander Volkanovski"], "fights": 2, "winner": "Islam Makhachev", "importance": "major", "summary": "Islam beat Volkanovski twice at lightweight. Volk gets upward-division context, but Islam still owns the direct championship separation."}, "kamaru usman|leon edwards": {"fighters": ["Kamaru Usman", "Leon Edwards"], "fights": 3, "winner": "Leon Edwards", "importance": "major", "summary": "Usman beat Edwards early, but Edwards won the two title fights, including the head-kick comeback. That rivalry is the main ceiling on Usman's welterweight case."}, "kamaru usman|colby covington": {"fighters": ["Kamaru Usman", "Colby Covington"], "fights": 2, "winner": "Kamaru Usman", "importance": "major", "summary": "Usman beat Covington twice in title fights, which is a major part of his welterweight title-run authority."}, "max holloway|dustin poirier": {"fighters": ["Max Holloway", "Dustin Poirier"], "fights": 2, "winner": "Dustin Poirier", "importance": "major", "summary": "Poirier beat Holloway twice, including their interim lightweight title fight. It matters, but Max's featherweight legacy still carries separate all-time weight."}, "jose aldo|frankie edgar": {"fighters": ["Jose Aldo", "Frankie Edgar"], "fights": 2, "winner": "Jose Aldo", "importance": "major", "summary": "Aldo beat Edgar twice in UFC featherweight title-level fights, which is a major part of Aldo's UFC resume."}, "jose aldo|chad mendes": {"fighters": ["Jose Aldo", "Chad Mendes"], "fights": 2, "winner": "Jose Aldo", "importance": "major", "summary": "Aldo beat Mendes twice, including an all-time classic rematch, which helps show Aldo's UFC title-level quality even with the WEC run excluded from scoring."}, "khabib nurmagomedov|dustin poirier": {"fighters": ["Khabib Nurmagomedov", "Dustin Poirier"], "fights": 1, "winner": "Khabib Nurmagomedov", "importance": "major", "summary": "Khabib submitted Poirier in a lightweight title defense, one of the key wins in Khabib's perfect compact reign."}, "khabib nurmagomedov|justin gaethje": {"fighters": ["Khabib Nurmagomedov", "Justin Gaethje"], "fights": 1, "winner": "Khabib Nurmagomedov", "importance": "major", "summary": "Khabib submitted Gaethje in his final UFC fight, closing his prime with one of the cleanest title-run finishes ever."}, "islam makhachev|charles oliveira": {"fighters": ["Islam Makhachev", "Charles Oliveira"], "fights": 1, "winner": "Islam Makhachev", "importance": "major", "summary": "Islam submitted Oliveira to win the lightweight title, giving him a defining championship win over an elite modern lightweight."}, "chuck liddell|randy couture": {"fighters": ["Chuck Liddell", "Randy Couture"], "fights": 3, "winner": "Chuck Liddell", "importance": "major", "summary": "Couture beat Chuck first, but Liddell won the next two by knockout and took the rivalry separation during the light heavyweight title era."}, "daniel cormier|stipe miocic": {"fighters": ["Daniel Cormier", "Stipe Miocic"], "fights": 3, "winner": "Stipe Miocic", "importance": "major", "summary": "Cormier knocked out Stipe first, but Stipe won the next two and took the heavyweight trilogy. That gives Stipe the direct rivalry edge."}, "daniel cormier|alexander gustafsson": {"fighters": ["Daniel Cormier", "Alexander Gustafsson"], "fights": 1, "winner": "Daniel Cormier", "importance": "major", "summary": "Cormier beat Gustafsson in a close light heavyweight title fight, one of the strongest defenses in DC's UFC title run."}, "francis ngannou|stipe miocic": {"fighters": ["Francis Ngannou", "Stipe Miocic"], "fights": 2, "winner": "Split", "importance": "major", "summary": "Stipe controlled Ngannou in their first title fight, then Ngannou knocked him out in the rematch. The split keeps both heavyweight cases connected."}, "alex pereira|israel adesanya": {"fighters": ["Alex Pereira", "Israel Adesanya"], "fights": 2, "winner": "Split", "importance": "major", "summary": "Pereira stopped Adesanya to win the middleweight title, then Adesanya knocked Pereira out in the rematch to regain it. In UFC terms, the rivalry is split."}, "israel adesanya|robert whittaker": {"fighters": ["Israel Adesanya", "Robert Whittaker"], "fights": 2, "winner": "Israel Adesanya", "importance": "major", "summary": "Adesanya beat Whittaker twice, first to unify the middleweight title and later to defend it. Those wins are central to Izzy's title-era case."}, "israel adesanya|marvin vettori": {"fighters": ["Israel Adesanya", "Marvin Vettori"], "fights": 2, "winner": "Israel Adesanya", "importance": "contextual", "summary": "Adesanya beat Vettori twice, including a clear middleweight title defense, which helps show his repeated control over the division."}, "b.j. penn|matt hughes": {"fighters": ["B.J. Penn", "Matt Hughes"], "fights": 3, "winner": "B.J. Penn", "importance": "major", "summary": "Penn beat Hughes twice, including the welterweight title upset, while Hughes won the middle fight. The series is a huge part of Penn's two-division argument."}, "b.j. penn|georges st-pierre": {"fighters": ["B.J. Penn", "Georges St-Pierre"], "fights": 2, "winner": "Georges St-Pierre", "importance": "major", "summary": "GSP beat Penn twice, including a dominant championship rematch, which creates clear separation between them in the all-time debate."}, "chuck liddell|tito ortiz": {"fighters": ["Chuck Liddell", "Tito Ortiz"], "fights": 2, "winner": "Chuck Liddell", "importance": "major", "summary": "Liddell beat Ortiz twice in major light heavyweight rivalry fights, including a title defense that helped define Chuck's championship era."}, "alex pereira|jiri prochazka": {"fighters": ["Alex Pereira", "Jiri Prochazka"], "fights": 2, "winner": "Alex Pereira", "importance": "major", "summary": "Pereira beat Prochazka twice in light heavyweight title fights, giving Alex a clean rivalry edge over one of the division's most dangerous champions."}, "alex pereira|jan blachowicz": {"fighters": ["Alex Pereira", "Jan Blachowicz"], "fights": 1, "winner": "Alex Pereira", "importance": "contextual", "summary": "Pereira beat Blachowicz in his light heavyweight debut, a key bridge win before Alex became champion in the division."}, "alex pereira|jamahal hill": {"fighters": ["Alex Pereira", "Jamahal Hill"], "fights": 1, "winner": "Alex Pereira", "importance": "major", "summary": "Pereira knocked out Hill in a light heavyweight title fight, adding a former champion to his short but loud title resume."}, "alexander volkanovski|ilia topuria": {"fighters": ["Alexander Volkanovski", "Ilia Topuria"], "fights": 1, "winner": "Ilia Topuria", "importance": "major", "summary": "Topuria knocked out Volkanovski to win the featherweight title, giving Ilia a direct era-shifting win over one of the division's greatest champions."}, "ilia topuria|max holloway": {"fighters": ["Ilia Topuria", "Max Holloway"], "fights": 1, "winner": "Ilia Topuria", "importance": "major", "summary": "Topuria beat Holloway in a major featherweight legacy fight. Max still owns the longer all-time resume, but Ilia owns the direct result."}, "ciryl gane|francis ngannou": {"fighters": ["Ciryl Gane", "Francis Ngannou"], "fights": 1, "winner": "Francis Ngannou", "importance": "major", "summary": "Ngannou beat Gane in a heavyweight title defense, showing a more patient and wrestling-aware version of his championship game."}, "curtis blaydes|francis ngannou": {"fighters": ["Curtis Blaydes", "Francis Ngannou"], "fights": 2, "winner": "Francis Ngannou", "importance": "contextual", "summary": "Ngannou beat Blaydes twice, both by stoppage, which is important because Blaydes was one of the division's toughest wrestling tests."}, "jose aldo|merab dvalishvili": {"fighters": ["Jose Aldo", "Merab Dvalishvili"], "fights": 1, "winner": "Merab Dvalishvili", "importance": "major", "summary": "Merab beat Aldo in a key bantamweight contender fight, giving him a direct win over a featherweight legend during Aldo's late elite run."}, "henry cejudo|merab dvalishvili": {"fighters": ["Henry Cejudo", "Merab Dvalishvili"], "fights": 1, "winner": "Merab Dvalishvili", "importance": "major", "summary": "Merab beat Cejudo, adding a two-division champion to his modern bantamweight resume."}, "merab dvalishvili|petr yan": {"fighters": ["Merab Dvalishvili", "Petr Yan"], "fights": 2, "winner": "Split", "importance": "major", "summary": "Merab beat Yan over five rounds in 2023 with pace, wrestling pressure, and control. Yan then beat Merab by unanimous decision at UFC 323 to reclaim the bantamweight title, making the rivalry a split series instead of a one-way direct edge."}, "merab dvalishvili|sean o'malley": {"fighters": ["Merab Dvalishvili", "Sean O'Malley"], "fights": 2, "winner": "Merab Dvalishvili", "importance": "major", "summary": "Merab beat O'Malley twice in title fights, giving him direct championship separation over one of the era's biggest bantamweight stars."}, "merab dvalishvili|umar nurmagomedov": {"fighters": ["Merab Dvalishvili", "Umar Nurmagomedov"], "fights": 1, "winner": "Merab Dvalishvili", "importance": "major", "summary": "Merab beat Umar in a high-level bantamweight title fight, adding major modern-division value to his championship case."}, "amanda nunes|valentina shevchenko": {"fighters": ["Amanda Nunes", "Valentina Shevchenko"], "fights": 2, "winner": "Amanda Nunes", "importance": "major", "summary": "Nunes beat Shevchenko twice, including a close title fight. Valentina's case stays elite, but Amanda owns the direct edge in the women's GOAT debate."}, "amanda nunes|ronda rousey": {"fighters": ["Amanda Nunes", "Ronda Rousey"], "fights": 1, "winner": "Amanda Nunes", "importance": "major", "summary": "Nunes finished Rousey quickly in a bantamweight title fight, a symbolic passing-of-the-torch moment in women's UFC history."}, "amanda nunes|cris cyborg": {"fighters": ["Amanda Nunes", "Cris Cyborg"], "fights": 1, "winner": "Amanda Nunes", "importance": "major", "summary": "Nunes knocked out Cyborg to win the featherweight title, one of the biggest wins in women's MMA history and a huge part of Amanda's two-division case."}, "amanda nunes|julianna pena": {"fighters": ["Amanda Nunes", "Julianna Pena"], "fights": 2, "winner": "Split", "importance": "major", "summary": "Pena upset Nunes in one of the biggest shocks in UFC title history, then Nunes dominated the rematch to take the belt back. The loss matters, but the revenge win stabilizes Amanda's case."}, "joanna jedrzejczyk|valentina shevchenko": {"fighters": ["Joanna Jedrzejczyk", "Valentina Shevchenko"], "fights": 1, "winner": "Valentina Shevchenko", "importance": "major", "summary": "Valentina beat Joanna to win the flyweight title, giving her a direct championship win over one of the great strawweight champions."}, "alexa grasso|valentina shevchenko": {"fighters": ["Alexa Grasso", "Valentina Shevchenko"], "fights": 3, "winner": "Split", "importance": "major", "summary": "Grasso submitted Valentina to end her reign, they fought to a draw in the rematch, and Valentina later regained the title. The series adds real late-career complexity to Valentina's case."}, "b.j. penn|frankie edgar": {"fighters": ["Frankie Edgar", "B.J. Penn"], "fights": 3, "winner": "Frankie Edgar", "importance": "major", "summary": "Edgar beat Penn three times in UFC competition, including the lightweight title win and the rematch defense. Penn can still have the bigger total two-division legacy case, but Frankie owns the direct UFC series."}, "frankie edgar|max holloway": {"fighters": ["Frankie Edgar", "Max Holloway"], "fights": 1, "winner": "Max Holloway", "importance": "major", "summary": "Holloway beat Edgar in a featherweight title fight, one of the ceiling fights on Frankie\u2019s late prime/title-relevance r\u00e9sum\u00e9."}, "frankie edgar|jose aldo": {"fighters": ["Frankie Edgar", "Jose Aldo"], "fights": 2, "winner": "Jose Aldo", "importance": "major", "summary": "Aldo beat Edgar twice in UFC featherweight title-level fights. Those losses are a major reason Frankie\u2019s excellent r\u00e9sum\u00e9 does not climb higher."}, "conor mcgregor|dustin poirier": {"fighters": ["Conor McGregor", "Dustin Poirier"], "fights": 3, "winner": "Dustin Poirier", "importance": "major", "summary": "McGregor won the first UFC meeting, but Poirier won the next two and took the overall UFC rivalry edge. That late series hurts Conor's back-end resume."}, "charles oliveira|dustin poirier": {"fighters": ["Dustin Poirier", "Charles Oliveira"], "fights": 1, "winner": "Charles Oliveira", "importance": "major", "summary": "Oliveira submitted Poirier in a lightweight title defense. Dustin owns more long-form lightweight depth; Charles owns the direct championship result."}, "dustin poirier|justin gaethje": {"fighters": ["Dustin Poirier", "Justin Gaethje"], "fights": 2, "winner": "Split", "importance": "major", "summary": "Poirier stopped Gaethje first, then Gaethje knocked out Poirier in the rematch. Their rivalry is split and central to both modern lightweight r\u00e9sum\u00e9s."}, "conor mcgregor|nate diaz": {"fighters": ["Conor McGregor", "Nate Diaz"], "fights": 2, "winner": "Split", "importance": "major", "summary": "Diaz submitted McGregor first, then McGregor won the rematch by decision. The rivalry is split and mostly adds context to Conor's risk-taking at welterweight."}, "colby covington|kamaru usman": {"fighters": ["Colby Covington", "Kamaru Usman"], "fights": 2, "winner": "Kamaru Usman", "importance": "major", "summary": "Usman beat Covington twice in welterweight title fights, giving him clean rivalry separation over one of his strongest era rivals."}, "kamaru usman|tyron woodley": {"fighters": ["Kamaru Usman", "Tyron Woodley"], "fights": 1, "winner": "Kamaru Usman", "importance": "major", "summary": "Usman dominated Woodley to win the welterweight title, a major passing-of-the-torch win in the modern 170-pound lineage."}, "gilbert burns|kamaru usman": {"fighters": ["Gilbert Burns", "Kamaru Usman"], "fights": 1, "winner": "Kamaru Usman", "importance": "major", "summary": "Usman stopped Burns in a welterweight title defense, adding a dangerous prime contender to his championship resume."}, "kamaru usman|jorge masvidal": {"fighters": ["Kamaru Usman", "Jorge Masvidal"], "fights": 2, "winner": "Kamaru Usman", "importance": "contextual", "summary": "Usman beat Masvidal twice in title fights, first over five rounds and then by knockout, strengthening the title-defense volume of his reign."}, "demetrious johnson|dominick cruz": {"fighters": ["Demetrious Johnson", "Dominick Cruz"], "fights": 1, "winner": "Dominick Cruz", "importance": "major", "summary": "Cruz beat Johnson in a UFC bantamweight title fight before Johnson became the flyweight standard. It gives Cruz a huge direct win, with division context attached."}, "dominick cruz|t.j. dillashaw": {"fighters": ["Dominick Cruz", "T.J. Dillashaw"], "fights": 1, "winner": "Dominick Cruz", "importance": "major", "summary": "Cruz beat Dillashaw to regain the bantamweight title after years of injuries, one of the most important comeback wins in UFC championship history."}, "dominick cruz|urijah faber": {"fighters": ["Dominick Cruz", "Urijah Faber"], "fights": 2, "winner": "Dominick Cruz", "importance": "major", "summary": "In UFC-only terms, Cruz beat Faber twice, including a title fight. Their WEC meeting is historical context, but not scored in this UFC-only ledger."}, "henry cejudo|t.j. dillashaw": {"fighters": ["Henry Cejudo", "T.J. Dillashaw"], "fights": 1, "winner": "Henry Cejudo", "importance": "major", "summary": "Cejudo stopped Dillashaw in a flyweight title defense, adding a champion-versus-champion style win to Henry's compact title run."}, "henry cejudo|marlon moraes": {"fighters": ["Henry Cejudo", "Marlon Moraes"], "fights": 1, "winner": "Henry Cejudo", "importance": "major", "summary": "Cejudo beat Moraes to win the vacant bantamweight title, completing the two-division championship piece of his UFC case."}, "brock lesnar|cain velasquez": {"fighters": ["Brock Lesnar", "Cain Velasquez"], "fights": 1, "winner": "Cain Velasquez", "importance": "major", "summary": "Cain stopped Lesnar to win the heavyweight title, one of the defining wins of his peak-pressure case."}, "cain velasquez|junior dos santos": {"fighters": ["Cain Velasquez", "Junior dos Santos"], "fights": 3, "winner": "Cain Velasquez", "importance": "major", "summary": "Dos Santos knocked Cain out first, but Cain won the next two title fights in dominant fashion, taking clear trilogy separation."}, "cain velasquez|fabricio werdum": {"fighters": ["Cain Velasquez", "Fabricio Werdum"], "fights": 1, "winner": "Fabricio Werdum", "importance": "major", "summary": "Werdum submitted Cain to win the heavyweight title, a major ceiling fight on Cain's all-time heavyweight resume."}, "cain velasquez|francis ngannou": {"fighters": ["Cain Velasquez", "Francis Ngannou"], "fights": 1, "winner": "Francis Ngannou", "importance": "contextual", "summary": "Ngannou beat Cain late in Cain's injury-damaged career. It is a direct result, but it should be treated with post-prime context."}, "antonio silva|cain velasquez": {"fighters": ["Antonio Silva", "Cain Velasquez"], "fights": 2, "winner": "Cain Velasquez", "importance": "contextual", "summary": "Cain beat Bigfoot Silva twice, including a heavyweight title defense, showing the violent pressure style that defined his prime."}, "aljamain sterling|petr yan": {"fighters": ["Aljamain Sterling", "Petr Yan"], "fights": 2, "winner": "Aljamain Sterling", "importance": "major", "summary": "Sterling officially leads Yan 2-0, but the first title fight ended by DQ and the rematch was close enough that Yan needs special context instead of being treated like a normal 0-2 rivalry loss."}};
